const rows = $input.all().map(r => r.json);
const today = new Date().toISOString().split('T')[0];

// Count by status
const statusCounts = {};
const statuses = ['New','Enriching','Active','Replied','Not_Found','Duplicate','Closed'];
statuses.forEach(s => { statusCounts[s] = 0; });
rows.forEach(r => {
  const s = r.status || 'Unknown';
  statusCounts[s] = (statusCounts[s] || 0) + 1;
});

// Count by assigned_to
let jatinCount = 0, sakshamCount = 0;
rows.forEach(r => {
  if ((r.assigned_to || '').toLowerCase() === 'jatin') jatinCount++;
  else if ((r.assigned_to || '').toLowerCase() === 'saksham') sakshamCount++;
});

// Leads added today
const leadsToday = rows.filter(r => (r.date_added || '').startsWith(today)).length;

// Replies with category set today — approximate by status=Replied
const repliesToday = rows.filter(r => r.status === 'Replied' && (r.date_added || '').startsWith(today)).length;

return [{
  json: {
    statusCounts,
    jatinCount,
    sakshamCount,
    leadsToday,
    repliesToday,
    today,
    allRows: rows
  }
}];

const shStats = $input.first().json;
const sheetStats = $('Calculate Sheet Stats').first().json;

let sent = 0, opened = 0, replied = 0, bounced = 0;
let openRate = 'N/A', replyRate = 'N/A', bounceRate = 'N/A';
let saleshandyAvailable = true;

try {
  // Try to extract from various possible response shapes
  const data = shStats.data || shStats.analytics || shStats;
  sent = data.sent || data.emailsSent || 0;
  opened = data.opened || data.emailsOpened || 0;
  replied = data.replied || data.emailsReplied || 0;
  bounced = data.bounced || data.emailsBounced || 0;

  if (sent > 0) {
    openRate = ((opened / sent) * 100).toFixed(1) + '%';
    replyRate = ((replied / sent) * 100).toFixed(1) + '%';
    bounceRate = ((bounced / sent) * 100).toFixed(1) + '%';
  }

  // If no meaningful data, mark as unavailable
  if (!shStats.data && !shStats.analytics && sent === 0) {
    saleshandyAvailable = false;
  }
} catch (e) {
  saleshandyAvailable = false;
}

return [{
  json: {
    ...sheetStats,
    saleshandyStats: { sent, opened, replied, bounced, openRate, replyRate, bounceRate },
    saleshandyAvailable
  }
}];

const repliesResponse = $input.first().json;
const statsData = $('Parse Campaign Stats').first().json;

let reconciled = 0;
let reconciliationSkipped = false;
const missedReplies = [];

try {
  const shReplies = repliesResponse.data || repliesResponse.replies || [];
  if (!Array.isArray(shReplies)) {
    reconciliationSkipped = true;
  } else {
    const allRows = statsData.allRows || [];

    for (const shReply of shReplies) {
      const shEmail = (shReply.prospect?.email || shReply.email || '').toLowerCase().trim();
      if (!shEmail) continue;

      // Check if this reply is in Sheet with status=Replied
      const alreadyRecorded = allRows.some(row => {
        return (row.email || '').toLowerCase().trim() === shEmail && row.status === 'Replied';
      });

      if (!alreadyRecorded) {
        missedReplies.push(shReply);
        reconciled++;
      }
    }
  }
} catch (e) {
  reconciliationSkipped = true;
}

return [{
  json: {
    ...statsData,
    reconciled,
    reconciliationSkipped,
    missedReplies
  }
}];

// Process missed replies through same logic as WF-02
const data = $input.first().json;
const missedReplies = data.missedReplies || [];

// For each missed reply, mark in sheet with default category INTERESTED
// (Full Claude classification would require separate API calls — we flag for manual review)
return missedReplies.map(reply => ({
  json: {
    email: reply.prospect?.email || reply.email || '',
    firstName: reply.prospect?.firstName || reply.firstName || '',
    company: reply.prospect?.company || reply.company || '',
    needsManualReview: true
  }
}));

const data = $('Reconcile Missed Replies').first().json;
const sc = data.statusCounts || {};
const sh = data.saleshandyStats || {};
const today = data.today || new Date().toISOString().split('T')[0];

let campaignLine = '';
if (!data.saleshandyAvailable) {
  campaignLine = '│ Saleshandy API unavailable\n';
} else {
  campaignLine = `│ Sent: ${sh.sent} | Opened: ${sh.opened} | Replied: ${sh.replied} | Bounced: ${sh.bounced}\n│ Open rate: ${sh.openRate} | Reply rate: ${sh.replyRate} | Bounce rate: ${sh.bounceRate}\n`;
}

let reconciledLine = '';
if (data.reconciliationSkipped) {
  reconciledLine = '│ Reconciliation skipped due to error\n';
} else {
  reconciledLine = `│ Reconciled (missed replies recovered): ${data.reconciled}\n`;
}

const digest = [
  '┌─ GE Outreach Daily Digest ──────────────',
  '│ Today\'s Activity',
  campaignLine.trimEnd(),
  '│',
  '│ Pipeline Status',
  `│ New: ${sc.New || 0} | Enriching: ${sc.Enriching || 0} | Active: ${sc.Active || 0} | Replied: ${sc.Replied || 0}`,
  `│ Closed: ${sc.Closed || 0} | Not Found: ${sc.Not_Found || 0} | Duplicate: ${sc.Duplicate || 0}`,
  '│',
  '│ By Owner',
  `│ Jatin: ${data.jatinCount || 0} active | Saksham: ${data.sakshamCount || 0} active`,
  '│',
  `│ Leads added today: ${data.leadsToday || 0}`,
  reconciledLine.trimEnd(),
  '└──────────────────────────────────────────'
].join('\n');

return [{ json: { digest } }];

